// Helper functions
export function countryCodeToFlag(code: string): string {
  return code
    .toUpperCase()
    .split("")
    .map((char) => String.fromCodePoint(char.charCodeAt(0) + 127397))
    .join("");
}

// Get daily player based on date
export function getDailyPlayer(): Player {
  const today = new Date();
  const daysSinceEpoch = Math.floor(today.getTime() / (1000 * 60 * 60 * 24));
  const index = daysSinceEpoch % players.length;
  return players[index];
}

// Get random player for unlimited mode
export function getRandomPlayer(excludeIds: number[] = []): Player {
  const available = players.filter((p) => !excludeIds.includes(p.id));
  if (available.length === 0) return players[Math.floor(Math.random() * players.length)];
  return available[Math.floor(Math.random() * available.length)];
}

// Get random player by difficulty
export function getRandomPlayerByDifficulty(difficulty: "easy" | "medium" | "hard", excludeIds: number[] = []): Player {
  const available = players.filter((p) => p.difficulty === difficulty && !excludeIds.includes(p.id));
  if (available.length === 0) return getRandomPlayer(excludeIds);
  return available[Math.floor(Math.random() * available.length)];
}

// Search players by name
export function searchPlayers(query: string): Player[] {
  if (!query || query.length < 2) return [];
  const lower = query.toLowerCase();
  return players
    .filter((p) => p.name.toLowerCase().includes(lower))
    .slice(0, 8);
}
